INSERT INTO `products` (`id`, `name`, `description`, `price`, `image`, `category_id`, `is_active`, `created_at`, `updated_at`, `avg_rating`, `review_count`) VALUES
(1, 'Беззерновой сухой корм холистик Wellement для стерилизованных кошек с индейкой и кроликом, 350 г', 'Состав\r\nМясо индейки (45%, из них 25% свежего мяса индейки и 20% дегидратированного мяса индейки), батат, нут, горох, белок гороха, дегидратированное мясо кролика (4%), масло лосося (2%), растительная клетчатка, гидролизованный белок курицы (1%), минералы, сушёный корень цикория, маннанолигосахариды и бета-глюканы, масло водорослевое, сушёная клюква, сушёный шпинат, сушёная морковь, сушёная черника, глюкозамин (100 мг/кг), хондроитина сульфат (100 мг/кг), сушёные травы (юкка Шидигера, расторопша, Rosmarinus sp., Curcuma sp., Citrus sp., Eugenia sp.).\r\nСырой протеин - 37,0% \r\nСырой жир - 12,0% \r\nСырая клетчатка - 3,0% \r\nВлажность - 6,0% \r\nМинеральные вещества - 7,5% \r\nКальций - 1,4% \r\nФосфор - 0,9% \r\nМагний - 0,09% \r\nНатрий - 0,4% \r\nКалий - 0,8% \r\nОмега-6 жирные кислоты - 2,0% \r\nОмега-3 жирные кислоты - 0,7% \r\nДобавки (на 1 кг)\r\nВитамин A 20 000 МЕ \r\nВитамин D3 1 750 МЕ \r\nВитамин E 200 мг\r\nВитамин В1 - 10,5 мг\r\nВитамин В2 - 8,3 мг\r\nВитамин В6 - 10,4 мг\r\nВитамин В12 - 50,7 мкг\r\nБиотин - 249 мкг\r\nФолиевая кислота - 4,0 мг\r\nТаурин 1 500 мг\r\nL-карнитин - 100 мг\r\nDL-метионин 5000 мг \r\nЖелезо (сульфат железа (II)) 50 мг \r\nЙод (йодат кальция) - 1,5 мг \r\nМедь (сульфат меди (II)) 10,0 мг \r\nМарганец (сульфат марганца) 10,0 мг \r\nЦинк (сульфат цинка) 60,0 мг, \r\nСелен (селенит натрия) 0,2 мг, ', 543.00, 'product_1772395650_69a49c82723d8.jpg', 1, 1, '2026-03-01 15:28:14', '2026-03-01 23:07:30', 0.00, 0),
(2, 'Беззерновой сухой корм холистик Wellement для котят с уткой, 1,5 кг', 'Состав\r\nСвежее мясо утки (23%), дегидратированное мясо индейки (23%), батат, нут, горох, жир индейки (7%), белок гороха, масло лосося (2%), гидролизованный белок курицы (1,5%), растительная клетчатка, минералы, сушеный корень цикория, маннанолигосахариды и бета-глюканы, сушёная клюква, сушёный шпинат, сушёная морковь, сушёная черника, глюкозамин (100 мг/кг), хондроитина сульфат (100 мг/кг), сушёные травы (юкка Шидигера, расторопша, Rosmarinus sp., Curcuma sp., Citrus sp., Eugenia sp.)\r\nСырой протеин - 34,0%\r\nСырой жиры - 18,0%\r\nСырая клетчатка - 3,0%\r\nВлажность - 6,0%\r\nМинеральные вещества - 7,0%\r\nКальций - 1,6%\r\nФосфор - 1,1%\r\nМагний - 0,09%\r\nНатрий - 0,4%\r\nКалий - 0,6%\r\nОмега-6 жирные кислоты - 3,0%\r\nОмега-3 жирные кислоты - 0,9%\r\nEPA+DHA - 0,4%\r\nДобавки (на 1 кг)\r\nВит. А - 20 000 МЕ\r\nВит. D3 - 1 750 МЕ\r\nВит. Е - 200 мг\r\nВит. В1 - 10,4 мг\r\nВит. В2 - 8,3 мг\r\nВит. В6 - 10,1 мг\r\nВит В12 - 50,2 мкг\r\nБиотин - 242 мкг\r\nФолиевая кислота - 4,0 мг\r\nТаурин - 1 250 мг\r\nDL-метионин - 5 000 мг\r\nЖелезо (сульфат железа II) - 50,0 мг\r\nЙод (йодат кальция) - 1,5 мг\r\nМедь (сульфат меди II) - 10,0 мг\r\nМарганец (сульфат марганца) - 10,0 мг\r\nЦинк (сульфат цинка) - 60,0 мг\r\nСелен (селенит натрия) - 0,2 мг\r\nEnterococcus faecium (пробиотик) - 109 КОЕ\r\nЭкстракт токоферолов из растительного масла (натуральный антиоксидант)', 1922.00, 'product_1772395661_69a49c8d01f23.jpg', 1, 1, '2026-03-01 15:34:26', '2026-03-01 23:07:41', 0.00, 0),
